// 輕量級前端多檔案上傳與檔名解析 JavaScript 範例
async function handleBillUploads(files) {
  const billsData = [];
  for (const file of files) {
    const name = file.name;
    const parts = name.replace(/\.[^/.]+$/, "").split("_");
    const bank = parts[0] || "未知銀行";
    const year = parts[1] || "2026";
    const month = parts[2] || "01";
    const billMonth = `${year}${month}`;

    const workbook = await readExcelFile(file);
    const rows = workbook.sheet[0].rows;
    rows.slice(1).forEach(row => {
      billsData.push({
        billMonth,
        bankName: bank,
        date: row[0],
        detail: row[2],
        amount: parseFloat(row[3]) || 0,
        region: row[4]
      });
    });
  }
  return billsData;
}
